def _calendar_zone():
    tz_name = getattr(settings, "CALENDAR_TIME_ZONE", "America/Denver")
    try:
        return ZoneInfo(tz_name)
    except Exception:
        return ZoneInfo("America/Denver")


def _derive_activity_date(dt):
    if dt is None:
        return None
    return dt.astimezone(_calendar_zone()).date()


