def _cleanup_cardio_routines(apps, schema_editor):
    CardioRoutine = apps.get_model("app_workout", "CardioRoutine")
    CardioWorkout = apps.get_model("app_workout", "CardioWorkout")
    CardioPlan = apps.get_model("app_workout", "CardioPlan")
    CardioDailyLog = apps.get_model("app_workout", "CardioDailyLog")

    keep_names = {"5K Prep", "Sprints", "Rest"}
    five_k = CardioRoutine.objects.filter(name="5K Prep").first()
    sprints = CardioRoutine.objects.filter(name="Sprints").first()

    for routine in list(CardioRoutine.objects.exclude(name__in=keep_names)):
        name_lower = (routine.name or "").strip().lower()
        target = None
        if "sprint" in name_lower:
            target = sprints
        elif "5k" in name_lower or "marathon" in name_lower:
            target = five_k

        workout_ids = list(CardioWorkout.objects.filter(routine_id=routine.pk).values_list("id", flat=True))
        has_logs = bool(workout_ids and CardioDailyLog.objects.filter(workout_id__in=workout_ids).exists())

        if target and has_logs:
            CardioWorkout.objects.filter(routine_id=routine.pk).update(routine_id=target.pk)
            CardioPlan.objects.filter(routine_id=routine.pk).update(routine_id=target.pk)
            routine.delete()
            continue

        if not has_logs:
            CardioWorkout.objects.filter(routine_id=routine.pk).delete()
            CardioPlan.objects.filter(routine_id=routine.pk).delete()
            routine.delete()


